import React, {useEffect, useRef, useState} from "react";

import DynamicParameterCard from "../components/DataEntity/DynamicParameterCard";
import ChatComponent from "../components/ChatComponent/ChatComponent";


function Testpage() {
    const [params, setParams] = useState({});
    const [renderData, setRenderData] = useState({})

    const ws = useRef(null);
    const [isConnected, setIsConnected] = useState(false);
    useEffect(() => {
        // WebSocket服务器地址 - 根据你的Python服务器修改
        const wsUrl = 'ws://localhost:8765';

        try {
            ws.current = new WebSocket(wsUrl);

            // 实际上发生了：
            // 1. 浏览器底层（C++实现）创建了真正的网络连接
            // 2. 这个网络连接运行在单独的线程中（浏览器管理）
            // 3. JavaScript主线程只是获得了对这个连接的引用
            ws.current.onopen = () => {
                console.log('WebSocket连接成功');
                setIsConnected(true);
            };

            ws.current.onclose = () => {
                console.log('WebSocket连接关闭');
                setIsConnected(false);
            };

            ws.current.onerror = (error) => {
                console.error('WebSocket错误:', error);
                setIsConnected(false);
            };

            // 接收消息
            // 这些事件监听器是回调函数，不是阻塞操作
            ws.current.onmessage = (event) => {
                setRenderData(event.data);// 当消息到达时，浏览器会调用这个函数
            };

            // 执行流程：
            // 主线程 → 注册回调 → 继续执行后续代码 → 事件循环等待
            // ↓
            // 当WebSocket消息到达时 → 浏览器将回调放入事件队列 → 主线程在空闲时执行回调


        } catch (error) {
            console.error('创建WebSocket连接失败:', error);
        }

        // 清理函数
        return () => {
            if (ws.current) {
                ws.current.close();
            }
        };
    }, []);

    const send = ()=>{
        console.log(123123123)
        ws.current.send(JSON.stringify("page_init"));
    }

    return (
        <div>
            {/*<DynamicParameterCard*/}
            {/*    RenderConfig={renderData}*/}
            {/*    params={params}*/}
            {/*    setParams={setParams}*/}
            {/*/>*/}
            {/*{isConnected && send()}*/}
            <ChatComponent/>
        </div>
    )
}

export default Testpage
